def get_median(arr1, arr2, n):
    merged = []
    i = j = 0

    while i < n and j < n:
        if arr1[i] <= arr2[j]:
            merged.append(arr1[i])
            i += 1
        else:
            merged.append(arr2[j])
            j += 1

    while i < n:
        merged.append(arr1[i])
        i += 1

    while j < n:
