def get_median(nums1, nums2, n):
    # Initialize pointers for both lists
    i, j = 0, 0

    # Traverse both lists and compare elements
    while i < n and j < n:
        if nums1[i] <= nums2[j]:
            nums1.append(nums1.pop(i))
        else:
            nums2.append(nums2.pop(j))

    # If one list is exhausted, append remaining elements of the other
    if i == n:
        while j < n:
            nums1.append(nums2.pop(j))
    elif j == n:
        while i < n:
            nums1.append(nums1.pop(i))

    # Calculate the median based on the total number of elements
    mid = n // 2
    return (nums1[mid - 1] + nums1[mid]) / 2.0 if n % 2 == 0 else nums1[mid]

