    n = len(arr)

    # Build a maxheap (a complete binary tree with all nodes greater than their children)
    for i in range(n//2 - 1, -1, -1):
        heapify(arr, n, i)

    # One by one extract elements from heap
    for i in range(n-1, 0, -1):
        arr[i], arr[0] = arr[0], arr[i]  # swap
        heapify(arr, i, 0)  # Heapify root element to get highest at top

    return arr

