def heap_sort(arr):
    def sift_down(start, end):
        root = start
        while True:
            left = 2 * root + 1
            right = 2 * root + 2
            largest = root

            if left <= end and arr[left] > arr[largest]:
                largest = left

            if right <= end and arr[right] > arr[largest]:
                largest = right

            if largest != root:
                arr[root], arr[largest] = arr[largest], arr[root]
                root = largest
            else:
                break

    n = len(arr)
    # Build the max-heap
    for i in range(n // 2 - 1, -1, -1):
        sift_down(i, n - 1)

